// Aşpazın mətbəxi obyekti
let kitchen = {
  chefName: "Aysel",
  dish: "Omlet",
  tool: "tava",
  cook: function() {
    return this.chefName + " " + this.dish + " hazırlayır!";
  }
};
console.log(kitchen.chefName); // nəticə: Aysel
console.log(kitchen.cook()); // nəticə: Aysel Omlet hazırlayır!

// Obyektə daxil olma və dəyişdirmə
let kitchen = {
  chefName: "Aysel",
  dish: "Omlet"
};
console.log(kitchen["dish"]); // nəticə: Omlet
kitchen.dish = "Pancake"; // dəyişdirmə
console.log(kitchen.dish); // nəticə: Pancake
kitchen.tool = "tava"; // yeni açar əlavə
console.log(kitchen); // nəticə: { chefName: "Aysel", dish: "Pancake", tool: "tava" }

// Obyektdə müxtəlif dəyərlər
let kitchen = {
  chefName: "Aysel",
  ingredients: ["yumurta", "süd"],
  tools: { tava: "böyük", çaydan: "kiçik" },
  cook: function() {
    return "Hazırlanan yemək: " + this.ingredients[0];
  }
};
console.log(kitchen.tools.tava); // nəticə: böyük
console.log(kitchen.cook()); // nəticə: Hazırlanan yemək: yumurta

// Obyekt vs Array
let kitchenObject = { chefName: "Aysel", dish: "Omlet" };
let kitchenArray = ["Aysel", "Omlet"];
console.log(kitchenObject.chefName); // nəticə: Aysel
console.log(kitchenArray[0]); // nəticə: Aysel
// Obyektdə açar adları mənalıdır, array-də isə indekslər

// Obyekt metodları
let kitchen = { chefName: "Aysel", dish: "Omlet", tool: "tava" };
console.log(Object.keys(kitchen)); // nəticə: ["chefName", "dish", "tool"]
console.log(Object.values(kitchen)); // nəticə: ["Aysel", "Omlet", "tava"]
console.log(Object.entries(kitchen)); // nəticə: [["chefName", "Aysel"], ["dish", "Omlet"], ["tool", "tava"]]
let newTools = { spoon: "böyük" };
Object.assign(kitchen, newTools);
console.log(kitchen); // nəticə: { chefName: "Aysel", dish: "Omlet", tool: "tava", spoon: "böyük" }

// Açar səhvi
let kitchen = { chefName: "Aysel" };
console.log(kitchen.name); // nəticə: undefined

// Daxili obyekt
let complexKitchen = {
  chef: { name: "Aysel", experience: 5 },
  dish: "Omlet"
};
console.log(complexKitchen.chef.name); // nəticə: Aysel

