// Chef’s kitchen object
let kitchen = {
  chefName: "Aysel",
  dish: "Omelette",
  tool: "pan",
  cook: function() {
    return this.chefName + " is cooking " + this.dish + "!";
  }
};
console.log(kitchen.chefName); // Output: Aysel
console.log(kitchen.cook()); // Output: Aysel is cooking Omelette!

// Accessing and modifying an object
let kitchen = {
  chefName: "Aysel",
  dish: "Omelette"
};
console.log(kitchen["dish"]); // Output: Omelette
kitchen.dish = "Pancake"; // Modify
console.log(kitchen.dish); // Output: Pancake
kitchen.tool = "pan"; // Add new key
console.log(kitchen); // Output: { chefName: "Aysel", dish: "Pancake", tool: "pan" }

// Objects with mixed values
let kitchen = {
  chefName: "Aysel",
  ingredients: ["eggs", "milk"],
  tools: { pan: "large", kettle: "small" },
  cook: function() {
    return "Cooking: " + this.ingredients[0];
  }
};
console.log(kitchen.tools.pan); // Output: large
console.log(kitchen.cook()); // Output: Cooking: eggs

// Object vs Array
let kitchenObject = { chefName: "Aysel", dish: "Omelette" };
let kitchenArray = ["Aysel", "Omelette"];
console.log(kitchenObject.chefName); // Output: Aysel
console.log(kitchenArray[0]); // Output: Aysel
// Objects use meaningful keys, arrays use indices

// Object methods
let kitchen = { chefName: "Aysel", dish: "Omelette", tool: "pan" };
console.log(Object.keys(kitchen)); // Output: ["chefName", "dish", "tool"]
console.log(Object.values(kitchen)); // Output: ["Aysel", "Omelette", "pan"]
console.log(Object.entries(kitchen)); // Output: [["chefName", "Aysel"], ["dish", "Omelette"], ["tool", "pan"]]
let newTools = { spoon: "large" };
Object.assign(kitchen, newTools);
console.log(kitchen); // Output: { chefName: "Aysel", dish: "Omelette", tool: "pan", spoon: "large" }

// Key error
let kitchen = { chefName: "Aysel" };
console.log(kitchen.name); // Output: undefined

// Nested object
let complexKitchen = {
  chef: { name: "Aysel", experience: 5 },
  dish: "Omelette"
};
console.log(complexKitchen.chef.name); // Output: Aysel

