// Кухня повара как объект
let kitchen = {
  chefName: "Айсель",
  dish: "Омлет",
  tool: "сковорода",
  cook: function() {
    return this.chefName + " готовит " + this.dish + "!";
  }
};
console.log(kitchen.chefName); // Вывод: Айсель
console.log(kitchen.cook()); // Вывод: Айсель готовит Омлет!

// Доступ и изменение объекта
let kitchen = {
  chefName: "Айсель",
  dish: "Омлет"
};
console.log(kitchen["dish"]); // Вывод: Омлет
kitchen.dish = "Блины"; // Изменение
console.log(kitchen.dish); // Вывод: Блины
kitchen.tool = "сковорода"; // Добавление ключа
console.log(kitchen); // Вывод: { chefName: "Айсель", dish: "Блины", tool: "сковорода" }

// Объекты с разными значениями
let kitchen = {
  chefName: "Айсель",
  ingredients: ["яйца", "молоко"],
  tools: { pan: "большая", kettle: "маленький" },
  cook: function() {
    return "Готовим: " + this.ingredients[0];
  }
};
console.log(kitchen.tools.pan); // Вывод: большая
console.log(kitchen.cook()); // Вывод: Готовим: яйца

// Объект vs Массив
let kitchenObject = { chefName: "Айсель", dish: "Омлет" };
let kitchenArray = ["Айсель", "Омлет"];
console.log(kitchenObject.chefName); // Вывод: Айсель
console.log(kitchenArray[0]); // Вывод: Айсель
// Объекты используют понятные ключи, массивы – индексы

// Методы объектов
let kitchen = { chefName: "Айсель", dish: "Омлет", tool: "сковорода" };
console.log(Object.keys(kitchen)); // Вывод: ["chefName", "dish", "tool"]
console.log(Object.values(kitchen)); // Вывод: ["Айсель", "Омлет", "сковорода"]
console.log(Object.entries(kitchen)); // Вывод: [["chefName", "Айсель"], ["dish", "Омлет"], ["tool", "сковорода"]]
let newTools = { spoon: "большая" };
Object.assign(kitchen, newTools);
console.log(kitchen); // Вывод: { chefName: "Айсель", dish: "Омлет", tool: "сковорода", spoon: "большая" }

// Ошибка ключа
let kitchen = { chefName: "Айсель" };
console.log(kitchen.name); // Вывод: undefined

// Вложенный объект
let complexKitchen = {
  chef: { name: "Айсель", experience: 5 },
  dish: "Омлет"
};
console.log(complexKitchen.chef.name); // Вывод: Айсель

